sys_script_include.script:
var McTaskUtil = Class.create();
McTaskUtil.prototype = {
    initialize: function() {
    },

	getDailyThroughput: function(tableName,dateField,encodedQuery) {
		gs.info('Berechne Throughput. Tabelle: ' + tableName + ', Datumsfeld: ' + dateField + ', Query:' + encodedQuery);

        // Finde den frühesten Start- und spätesten Endzeitpunkt
        var startDate = new GlideDateTime();
        var endDate = new GlideDateTime();

        var gaDateRange = new GlideAggregate(tableName);
        gaDateRange.addAggregate('MIN', dateField);
        gaDateRange.addAggregate('MAX', dateField);
		gaDateRange.addEncodedQuery(encodedQuery);
		gaDateRange.setGroup(false);
        gaDateRange.query();
        if (gaDateRange.next()) {
            startDate = new GlideDateTime(gaDateRange.getAggregate('MIN', dateField));
            endDate = new GlideDateTime(gaDateRange.getAggregate('MAX', dateField));
			gs.info('Start: ' + startDate + 'Ende: ' + endDate);
        }

        // Initialisiere das Durchsatz-Map mit Nullwerten
        var throughputMap = {};
        var currentDate = new GlideDateTime(startDate);
        while (currentDate.getNumericValue() <= endDate.getNumericValue()) {
            throughputMap[currentDate.getLocalDate()] = 0; // Jeder Tag bekommt den Startwert 0
            currentDate.addDaysLocalTime(1);
        }

        var grTask = new GlideRecord(tableName);
        grTask.addQuery(dateField, '!=', ''); // Nur Stories mit definiertem Enddatum
        grTask.addEncodedQuery(encodedQuery) ;
        grTask.query();

        while (grTask.next()) {
            var targetDate = new GlideDateTime(grTask.getValue(dateField)).getLocalDate();
            if (throughputMap[targetDate] !== undefined) {
                throughputMap[targetDate] += 1; // Inkrementiere den Durchsatz für diesen Tag
            }
        }

        // Konvertiere die Map in ein Array (inkl. Tage mit 0 Durchsatz wie Wochenenden)
        var dailyThroughput = Object.values(throughputMap);

        // Debugging: Ausgabe der täglichen Durchsatzdaten
        gs.info("Daily Throughput Data: " + JSON.stringify(dailyThroughput));

        return dailyThroughput;
    },

    type: 'McTaskUtil'
};
